public int findK(int[] nums) {
    Set<Integer> set = new HashSet<>();
    for (int num : nums) {
        set.add(num);
    }
    int k = -1;
    for (int num : nums) {
        if (set.contains(-num)) {
            k = Math.max(k, Math.abs(num));
        }
    }
    return k;
}
```


